// src/pages/HomeScreen.js
import React from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TouchableOpacity,
  ScrollView,
} from "react-native";
import { useNavigation } from "@react-navigation/native";

// taxi.png already INCLUDES the big green check “pin”
const taxiImg = require("../../assets/taxi.png");

// urban.png already INCLUDES the “Communauté Urbaine de Yaoundé” text
const cityLogo = require("../../assets/urban.png");

const tickCircle = require("../../assets/tickcircle.png");
const shieldLock = require("../../assets/shieldd.png");

export default function HomeScreen() {
  const navigation = useNavigation();
  const plateNumber = "CE696KO";

  const goToOfficialControl = () => {
    // You said Home is the only screen for now, so keep this disabled
    // navigation.navigate("official-control");
  };

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView
        showsVerticalScrollIndicator={false}
        contentContainerStyle={styles.scrollContent}
      >
        <View style={styles.screen}>
          {/* ===== HERO (same proportions as mockup) ===== */}
          <View style={styles.heroWrap}>
            <View style={styles.faintCircle} />

            {/* Card exactly like mockup */}
            <View style={styles.heroCard}>
              <Image source={taxiImg} style={styles.taxi} resizeMode="contain" />
            </View>
          </View>

          {/* ===== STATUS ===== */}
          <View style={styles.statusRow}>
            <Image source={tickCircle} style={styles.smallTick} resizeMode="contain" />
            <Text style={styles.statusText}>Vérifié</Text>
          </View>

          {/* ===== PLATE ===== */}
          <View style={styles.plateWrap}>
            <Text style={styles.plateText}>{plateNumber}</Text>
          </View>

          {/* ===== BUTTON ===== */}
          <TouchableOpacity activeOpacity={0.92} style={styles.officialBtn} onPress={goToOfficialControl}>
            <Image source={shieldLock} style={styles.btnIcon} resizeMode="contain" />
            <Text style={styles.btnText}>Contrôle officiel</Text>
          </TouchableOpacity>

          {/* ===== LOGO (image already has text) ===== */}
          <View style={styles.logoWrap}>
            <Image source={cityLogo} style={styles.logo} resizeMode="contain" />
          </View>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

const GREEN = "#2F7D3A";
const DARK_GREEN = "#0F3C2F";

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#EEF3F7" },

  // ✅ This is what prevents the last logo from being cut off
  scrollContent: {
    paddingBottom: 70,
  },

  screen: {
    paddingTop: 18,
    paddingHorizontal: 18,
    alignItems: "center",
  },

  /* ===== HERO ===== */
  heroWrap: {
    width: "100%",
    height: 285,              // ✅ closer to mockup
    alignItems: "center",
    justifyContent: "center",
    position: "relative",
    marginTop: 6,
    marginBottom: 6,
  },

  faintCircle: {
    position: "absolute",
    width: 360,
    height: 360,
    borderRadius: 180,
    backgroundColor: "#DDE7F1",
    opacity: 0.40,
  },

  // ✅ rounded white card like mockup (not too huge)
  heroCard: {
    width: "86%",
    height: 195,
    borderRadius: 34,
    backgroundColor: "rgba(255,255,255,0.82)",
    padding: 14,
    alignItems: "center",
    justifyContent: "center",
    shadowColor: "#000",
    shadowOpacity: 0.10,
    shadowRadius: 22,
    shadowOffset: { width: 0, height: 14 },
    elevation: 7,
  },

  taxi: {
    width: "100%",
    height: "100%",
  },

  /* ===== STATUS ===== */
  statusRow: {
    flexDirection: "row",
    alignItems: "center",
    marginTop: 14,
    gap: 12,
  },
  smallTick: { width: 44, height: 44 },

  // ✅ reduced to match mockup (your previous was too big)
  statusText: {
    fontSize: 46,
    fontWeight: "900",
    color: GREEN,
    letterSpacing: 0.2,
  },

  /* ===== PLATE ===== */
  plateWrap: {
    marginTop: 18,
    width: "86%",
    borderRadius: 26,
    borderWidth: 5,
    borderColor: GREEN,
    backgroundColor: "#FFFFFF",
    paddingVertical: 16,
    alignItems: "center",
    shadowColor: "#000",
    shadowOpacity: 0.08,
    shadowRadius: 18,
    shadowOffset: { width: 0, height: 12 },
    elevation: 5,
  },
  plateText: {
    fontSize: 56,            // ✅ closer to mockup
    fontWeight: "900",
    letterSpacing: 1.2,
    color: "#111827",
  },

  /* ===== BUTTON ===== */
  officialBtn: {
    marginTop: 18,
    width: "86%",
    height: 78,              // ✅ like mockup
    backgroundColor: DARK_GREEN,
    borderRadius: 26,
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "center",
    gap: 12,
    shadowColor: "#000",
    shadowOpacity: 0.22,
    shadowRadius: 22,
    shadowOffset: { width: 0, height: 16 },
    elevation: 9,
  },
  btnIcon: { width: 22, height: 22, opacity: 0.95 },
  btnText: {
    color: "#FFFFFF",
    fontSize: 30,
    fontWeight: "900",
    letterSpacing: 0.2,
  },

  /* ===== LOGO ===== */
  logoWrap: {
    marginTop: 26,
    marginBottom: 18,        // ✅ extra space so it never cuts
    alignItems: "center",
    width: "100%",
  },
  logo: {
    width: 210,              // ✅ not too large + won’t cut
    height: 210,
  },
});
